// Integration tests for tensogram-netcdf.
// Tests are added incrementally as Tasks 6-12 implement the converter.
//
// Fixture files live in testdata/ — generated by testdata/generate.py.
// Run `python testdata/generate.py` to regenerate them.

fn testdata(name: &str) -> std::path::PathBuf {
    let mut path = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    path.push("testdata");
    path.push(name);
    path
}

// Placeholder test to verify the crate compiles and links.
#[test]
fn crate_compiles() {
    // Smoke test: just verify the crate links against libnetcdf.
    // Real tests are added in Tasks 6-12.
    let _ = testdata("simple_2d.nc");
}
